  await client.moveUid(uid, destinationMailbox);
} finally {
  await client.logout().catch(() => {});
}

return [{
  json: outputJson(item, {
    email_action_status: 'moved',
    email_action_destination: destinationMailbox,
    source_action: actionName,
  }),
}];

